import React from 'react';

export default function KonferansEkibi() {
  const teamMembers = [
    {
      id: 1,
      image: '/images/ekip/cemre.PNG',
      name: 'Rtc. Cemre Ertan',
      role: 'Bölge Rotaract Temsilcisi',
    },
    {
      id: 2,
      image: '/images/ekip/pınar.PNG',
      name: 'Rtc.Pınar Tektaş',
      role: 'Ankara Tandoğan Rotaract Kulübü Başkanı - Konaklama ve Karşılama Komitesi Başkanı',
    },
    {
      id: 3,
      image: '/images/ekip/ufuk.PNG',
      name: 'Rtc.Yusuf Ufuk Altınöz',
      role: 'Konferans Ana Komite Baskanı',
    },
    {
      id: 4,
      image: '/images/ekip/kagan.PNG',
      name: 'Rtc.Ahmet Kağan Kaya',
      role: 'Konferans Sekreteri - Sponsorluk Komitesi Başkanı',
    },
    {
      id: 5,
      image: '/images/ekip/ege.PNG',
      name: 'Rtc.Nejat Ege Ketrez',
      role: 'Konferans Saymanı',
    },
    {
      id: 6,
      image: '/images/ekip/eda.PNG',
      name: 'Rtc.Eda Damar',
      role: 'Sosyal Medya ve Tanıtım Komitesi Başkanı',
    },
    {
      id: 7,
      image: '/images/ekip/janset.PNG',
      name: 'Rtc.Janset Namlı',
      role: 'Bayrak Töreni Komitesi Başkanı',
    },
    {
      id: 8,
      image: '/images/ekip/arın.PNG',
      name: 'Rtc.Arın Akpınar',
      role: 'Ulaşım Komitesi Başkanı',
    },
    {
      id: 9,
      image: '/images/ekip/dilem.PNG',
      name: 'Rtc.Dilem Özdurmuş',
      role: 'Gala Komitesi Başkanı',
    },
    {
      id: 10,
      image: '/images/ekip/görkay.PNG',
      name: 'Rtc.Görkay Atmaca',
      role: 'Eğlence ve Takım Oyunları Komitesi Başkanı',
    },
    {
      id: 11,
      image: '/images/ekip/sarper.PNG',
      name: 'Rtc.Sarper Sarpkaya',
      role: 'Eğlence ve Takım Oyunları Komitesi Başkanı',
    },
  ];

  return (
    <section className="py-5">
      <div className="container">
        <h1 className="text-center mb-5" style={{marginTop: '50px'}}>Konferans Ekibi</h1>
        <div className="row">
          {teamMembers.map((member, idx) => (
            <div
              className={`col-md-6 mb-4 ${teamMembers.length % 2 === 1 && idx === teamMembers.length - 1 ? 'offset-md-3' : ''}`}
              key={member.id}
            >
              <div className="konf-ekip-card">
                <img
                  src={member.image}
                  className="img-fluid"
                  alt={member.name}
                />
                <div className="konf-ekip-caption">
                  <div className="konf-ekip-name">{member.name}</div>
                  <div className="konf-ekip-role">{member.role}</div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
